// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 205

int N;
int graph[MAXN][MAXN];
int visited[MAXN];
int low[MAXN];
int disc[MAXN];
int parent[MAXN];
int time = 0;
int bcc_count = 0;
int bcc_id[MAXN];

void dfs(int u) {
    visited[u] = 1;
    disc[u] = low[u] = time++;
    int children = 0;
    for (int v = 1; v <= N; v++) {
        if (graph[u][v]) {
            if (!visited[v]) {
                parent[v] = u;
                children++;
                dfs(v);
                low[u] = (low[u] < low[v]) ? low[u] : low[v];
                if (low[v] >= disc[u] && parent[u] != -1) {
                    bcc_count++;
                    bcc_id[u] = bcc_count;
                }
            } else if (v != parent[u]) {
                low[u] = (low[u] < disc[v]) ? low[u] : disc[v];
            }
        }
    }
}

int main() {
    scanf("%d", &N);
    for (int i = 1; i < N; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        graph[u][v] = graph[v][u] = 1;
    }
    for (int i = 1; i <= N; i++) {
        if (!visited[i]) {
            dfs(i);
        }
    }
    long long result[N + 1];
    for (int i = 1; i <= N; i++) {
        result[i] = 0;
    }
    for (int i = 1; i <= N; i++) {
        long long prob = 1;
        for (int j = 1; j <= N; j++) {
            if (i != j) {
                prob = (prob * (1 + (graph[i][j] ? 1 : 0))) % MOD;
            }
        }
        result[bcc_id[i]] = (result[bcc_id[i]] + prob) % MOD;
    }
    for (int i = 1; i <= N; i++) {
        printf("%lld ", result[i]);
    }
    printf("\n");
    return 0;
}

