import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static final int MAXN = 205;
    static int N;
    static int[][] graph = new int[MAXN][MAXN];
    static int[] visited = new int[MAXN];
    static int[] low = new int[MAXN];
    static int[] disc = new int[MAXN];
    static int[] parent = new int[MAXN];
    static int time = 0;
    static int bcc_count = 0;
    static int[] bcc_id = new int[MAXN];

    public static void dfs(int u) {
        visited[u] = 1;
        disc[u] = low[u] = time++;
        int children = 0;
        for (int v = 1; v <= N; v++) {
            if (graph[u][v] == 1) {
                if (visited[v] == 0) {
                    parent[v] = u;
                    children++;
                    dfs(v);
                    low[u] = Math.min(low[u], low[v]);
                    if (low[v] >= disc[u] && parent[u] != -1) {
                        bcc_count++;
                        bcc_id[u] = bcc_count;
                    }
                } else if (v != parent[u]) {
                    low[u] = Math.min(low[u], disc[v]);
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        for (int i = 1; i < N; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            graph[u][v] = graph[v][u] = 1;
        }
        for (int i = 1; i <= N; i++) {
            if (visited[i] == 0) {
                dfs(i);
            }
        }
        long[] result = new long[N + 1];
        for (int i = 1; i <= N; i++) {
            result[i] = 0;
        }
        for (int i = 1; i <= N; i++) {
            long prob = 1;
            for (int j = 1; j <= N; j++) {
                if (i != j) {
                    prob = (prob * (1 + (graph[i][j] == 1 ? 1 : 0))) % MOD;
                }
            }
            result[bcc_id[i]] = (result[bcc_id[i]] + prob) % MOD;
        }
        for (int i = 1; i <= N; i++) {
            System.out.print(result[i] + " ");
        }
        System.out.println();
    }
}

